const axios = require('axios');
const fs = require('fs');
const path = require('path');

const registrationNumber = process.argv[2];
const appId = process.env.PREMBLY_APP_ID;
const apiKey = process.env.PREMBLY_API_KEY;

if (!registrationNumber) {
    console.error('Please provide a registration number as a command-line argument.');
    process.exit(1);
}

if (!appId || !apiKey) {
    console.error('Environment variables PREMBLY_APP_ID and PREMBLY_API_KEY must be set.');
    process.exit(1);
}

const url = 'https://api.prembly.com/api/v1/biometrics/merchant/data/verification/cac';
const body = {
    company_type: 'RC',
    rc_number: registrationNumber
};

const headers = {
    'app-id': appId,
    'x-api-key': apiKey,
    'Content-Type': 'application/json'
};

const outputPath = path.join(__dirname, 'output.json');

async function verifyBusiness() {
    try {
        const response = await axios.post(url, body, { headers });
        fs.writeFileSync(outputPath, JSON.stringify(response.data, null, 2));
        console.log(`Response successfully written to ${outputPath}`);
    } catch (error) {
        const errorData = error.response ? error.response.data : { error: error.message };
        fs.writeFileSync(outputPath, JSON.stringify(errorData, null, 2));
        console.error(`Error occurred. Details written to ${outputPath}`);
        process.exit(1);
    }
}

verifyBusiness();

